import base64
b64_mdpi = ""
b64_hdpi = ""
b64_xhdpi = ""
b64_xxhdpi = ""

import os
for name, b64 in [("mdpi", b64_mdpi), ("hdpi", b64_hdpi), ("xhdpi", b64_xhdpi), ("xxhdpi", b64_xxhdpi)]:
    os.makedirs(f"app/src/main/res/mipmap-{name}", exist_ok=True)
    with open(f"app/src/main/res/mipmap-{name}/ic_launcher.png", "wb") as f:
        f.write(base64.b64decode(b64))
    print(f"Created mipmap-{name}/ic_launcher.png")
